import{_ as a,o as p,c as t,j as e,a as b,a1 as d}from"./chunks/framework.Bp7r_-XI.js";const h=JSON.parse('{"title":"Exceed-山火","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/6.套装/Transcend Fate/Exceed-山火.md","filePath":"4.资源分区/7.物品与装备/6.套装/Transcend Fate/Exceed-山火.md"}'),n={name:"4.资源分区/7.物品与装备/6.套装/Transcend Fate/Exceed-山火.md"};function c(s,r,o,l,_,i){return p(),t("div",null,[...r[0]||(r[0]=[e("h1",{id:"exceed-山火",tabindex:"-1"},[b("Exceed-山火 "),e("a",{class:"header-anchor",href:"#exceed-山火","aria-label":'Permalink to "Exceed-山火"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌039")])])],-1),d('<h1 id="exceed-山火-1" tabindex="-1">Exceed-山火 <a class="header-anchor" href="#exceed-山火-1" aria-label="Permalink to &quot;Exceed-山火&quot;">​</a></h1><p>Exceed-山火</p><p>武器：</p><p>讹火<br> B+3000</p><p>武器伤害：18L<br> 武器分类：武士刀<br> 武器体积：3<br> 武器特性：【破甲1】</p><p>描述：<br> 灾厄应对机构通过解析象征山火概念的灾厄兽【毕方】，研制出的武器。<br> “鬼車繞樹而能飛，訛火因風而明滅。”<br> 这是一把总长度约为100厘米的太刀，主体由未知的木制结构组成，</p><p>外观：<br> 外形焦枯如炭，刀身遍布天然形成的暗红色火纹，<br> 刀镡与刀柄则缠绕着一种色泽乌黑的羽毛。<br> 挥舞讹火时，刀过之处，空气中会短暂地留下燃烧的残影，<br> 并且不会有着破空声，只会发出火焰的噼啪声。</p><p>当使用讹火进行攻击时，其在攻击检定上的加骰下降1级，这不是一个劣化效果，不会优先劣化最高的加骰等级，最低降低至10加骰，若加骰本身已经为10加骰，则讹火的所有效果不生效，<br> 讹火的攻击命中时，敌人需以强韧豁免进行一次DC为28的强韧豁免，若失败，则受到差值点燃烧异常点数（最多3点），<br> 若携带讹火在2场同级战斗中获胜，那么其造成的伤害可以转化为等量的燃烧异常点数。</p><p>奇物：</p><p>天浊<br> B+3000<br> 占据斗篷位</p><p>描述：<br> 灾厄应对机构通过解析象征山火概念的灾厄兽【毕方】，研制出的斗篷。<br> “瘴氛恒積潤，天浊亟生煅。”<br> 这件披风由无数片无法辨其种类的漆黑羽毛编织而成，它们并非乌鸦或任何已知禽鸟之羽。</p><p>外观：<br> 羽毛的羽管中时不时闪烁出赤色的火光，并且有着难以置信的强韧，<br> 而自披风中段起，直至下摆边缘，则布满了大片大片仿佛被火焰舔舐过的灼痕。<br> 这些痕迹并非焦黄，而是一种暗沉的赭红色，如同地底深处将熄的余烬。<br> 当披风静止时，这些斑痕晦暗不明；一旦披风随风摆动，痕跡中便会有星点诡谲的“讹火” 骤然亮起，<br> 明灭闪烁，发出细微的、如同灼烧朽木的噼啪声，旋即又隐没于羽毛的漆黑之中。<br> 讹火的穿戴者在攻击检定上的加骰下降1级，这不是一个劣化效果，不会优先劣化最高的加骰等级，最低降低至10加骰，若加骰本身已经为10加骰，则讹火的所有效果不生效，<br> 讹火可以作为盾牌使用，此时其具有【格挡20】【双手】，使用【武技+刀】计算格挡防御，穿戴者常态处于格挡状态。</p><p>套这一套装不具有基础的套装效果，以下能力支付B+2000作为技艺进行购买</p><p>毕方</p><p>事件记录：<br> 我们都知道灾厄兽亦有其种群，至少一些灾厄兽有，除此之外，不同的灾厄兽个体之间几乎不会以任何形式交流，即使是相遇，要么互相战斗抢夺领域，要么一方退让，无事发生。<br> 但，凡事皆有例外，<br> 我们不止一次观测到它们，我们曾经认为它们是某种同族灾厄兽的不同个体，或是某种伴生大型灾厄的小型灾厄，然而事实总是出人意料，<br> 尽管它们可以说是互为天敌，它们仍然相互依偎，我们第一次见证了灾厄兽亦有其情绪……<br> 我们发现了这套装备，就在它的爱人的尸体旁边。</p><p>是的，代号为【讹火】的武装，其从来不出自人手，而是灾厄兽的自愿死亡。</p><p>“有鸟焉，其状如鹤，一足，赤文青质而白喙，名曰毕方，其鸣自叫也，见则其邑有讹火。”</p><p>获得【耐力属性】点偏斜防御，<br> 除此之外还会获得【耐力上的传奇属性】*1点偏斜防御上的附加成功，</p><p>在战斗中，可以消耗一个移动动作和10点东方能量使自己进入【炎狱】状态，持续一场景，战斗结束后状态结束，或者以一个移动动作主动结束。<br> 此时的讹火武器将会燃起橙红色的火焰，此时的讹火武器将会额外施加B级的重伤效果，<br> 讹火披风上的羽毛将会转变为橘红色，羽毛则会完全舒展，<br> 在【炎狱】状态下，穿戴者将会获得机动性为完美的飞行能力，讹火的攻击命中时的DC上升6点，一次性施加的最大燃烧点数额外上升5点（即上限8点）。<br> 福兮祸所依，这件直接由灾厄兽产生的武装会在【炎狱】状态下与穿戴者逐渐产生共同化，开启的首轮结束时，需要进行一次DC为4的强韧豁免，那之后，每轮结束时都需要进行一次DC为前一轮DC两倍的强韧豁免，若如此豁免失败，你会陷入不可避免无法免疫的B级附身来源的狂躁与混乱混合的狂化状态中，无差别攻击所有活物，直到自身失去行动能力为止。<br> 陷入狂化或主动解除状态都将重置该豁免DC。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',21)])])}const f=a(n,[["render",c]]);export{h as __pageData,f as default};
